    const auto result = query(conn);
  } else if (table_name == "Course") {
    const uint32_t id = static_cast<uint32_t>(std::stoul(record_id));
    const auto query = delete_from<Course> | where("CID"_c == id);
    const auto result = query(conn);
  } else if (table_name == "Score") {
    const uint32_t id = static_cast<uint32_t>(std::stoul(record_id));
