```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = std::move(conn_result.value());

  // Start a transaction for batch insertion
  auto transaction_result = sqlgen::begin_transaction(conn);
  if (!transaction_result) {
    throw std::runtime_error("Failed to start transaction");
  }

  try {
    // Insert each record
    for (const auto& record : records) {
      auto insert_result = sqlgen::insert(conn, record);
      if (!insert_result) {
        throw std::runtime_error("Failed to insert record");
      }
    }

    // Commit the transaction
    auto commit_result = sqlgen::commit_transaction(conn);
    if (!commit_result) {
      throw std::runtime_error("Failed to commit transaction");
    }
  } catch (...) {
    // Rollback on error
    sqlgen::rollback_transaction(conn);
    throw;
  }
}

template<typename T>
void modify_eas_records_by_id(const std::string& table_name,
                              int record_id,
                              const std::string& col_name,
                              const T& new_value) {

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = std::move(conn_result.value());

  // Map table names to their update functions and primary key fields
  static const std::map<std::string, std::string> primary_keys = {
    {"Student", "SNo"},
    {"Course", "CID"},
    {"Score", "ScID"},
    {"Major", "MID"}
  };

  auto it = primary_keys.find(table_name);
  if (it == primary_keys.end()) {
    throw std::runtime_error("Unknown table: " + table_name);
  }

  const std::string& pk_field = it->second;

  try {
    // Update based on table type
    if (table_name == "Student") {
      auto update_result = sqlgen::update(
        conn, 
        sqlgen::filter(sqlgen::column("SNo") == std::to_string(record_id)),
        sqlgen::set(sqlgen::column(col_name) = new_value)
      );
      if (!update_result) {
        throw std::runtime_error("Failed to update Student record");
      }
    }
    else if (table_name == "Course") {
      auto update_result = sqlgen::update(
        conn, 
        sqlgen::filter(sqlgen::column("CID") == record_id),
        sqlgen::set(sqlgen::column(col_name) = new_value)
      );
      if (!update_result) {
        throw std::runtime_error("Failed to update Course record");
      }
    }
    else if (table_name == "Score") {
      auto update_result = sqlgen::update(
        conn, 
        sqlgen::filter(sqlgen::column("ScID") == record_id),
        sqlgen::set(sqlgen::column(col_name) = new_value)
      );
      if (!update_result) {
        throw std::runtime_error("Failed to update Score record");
      }
    }
    else if (table_name == "Major") {
      auto update_result = sqlgen::update(
        conn, 
        sqlgen::filter(sqlgen::column("MID") == record_id),
        sqlgen::set(sqlgen::column(col_name) = new_value)
      );
      if (!update_result) {
        throw std::runtime_error("Failed to update Major record");
      }
    }
  } catch (const std::exception& e) {
    throw std::runtime_error(std::string("Update failed: ") + e.what());
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id) {

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = std::move(conn_result.value());

