    {"Student", "SNo"},
    {"Course", "CID"},
    {"Score", "ScID"},
    {"Major", "MID"}
  };

  auto it = primary_keys.find(table_name);
  if (it == primary_keys.end()) {
    throw std::runtime_error("Unknown table: " + table_name);
  }

  const std::string& pk_field = it->second;

  try {
    // Delete based on table type
    if (table_name == "Student") {
      auto delete_result = sqlgen::remove(
        conn, 
        sqlgen::filter(sqlgen::column("SNo") == record_id)
      );
      if (!delete_result) {
        throw std::runtime_error("Failed to delete Student record");
      }
    }
    else if (table_name == "Course") {
      int id = std::stoi(record_id);
      auto delete_result = sqlgen::remove(
        conn, 
        sqlgen::filter(sqlgen::column("CID") == id)
      );
