std::vector<CourseStats> query_course_enrollment_stats() {
  // Connect to the SQLite database
  sqlgen::SQLiteDB db("test_db.sqlite");

  // Create Course and Enrollment tables if they don't exist
  db.createTableIfNotExists<Course>();
  db.createTableIfNotExists<Enrollment>();

  // Query the database to calculate enrollment statistics
  auto results = db.query<CourseStatsView>(
    "SELECT c.title, COUNT(e.enrollment_id) as student_count, AVG(e.grade) as avg_grade "
    "FROM Course c "
    "LEFT JOIN Enrollment e ON c.course_id = e.course_id "
    "GROUP BY c.course_id, c.title"
