  // Convert the view results to CourseStats objects
  std::vector<CourseStats> stats;
  for (const auto& view : results) {
    CourseStats course_stat;
    course_stat.title = view.title;
    course_stat.student_count = view.student_count;
    course_stat.avg_grade = view.avg_grade;
    stats.push_back(std::move(course_stat));
  }

  return stats;
}

}  // namespace query_course_enrollment_stats
