    auto db = sqlgen::sqlite::connection::open("test_db.sqlite");

    // Build the query using sqlgen
    auto query = sqlgen::query<Product>()
        .inner_join<Sale>(sqlgen::on(Product::product_id == Sale::product_id))
        .group_by(Product::category)
        .having(sqlgen::sum(Sale::amount) > 5000.0)
        .select(
