#pragma once

#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace query_search_books_by_criteria {

struct Book {
  sqlgen::PrimaryKey<int> book_id;
  std::string title;
  std::string author;
  int year;
  std::string genre;
  double price;
};

struct BookFilters {
  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    // Create database connection
    sqlgen::SQLiteDB db("test_db.sqlite");

    // Start with base SELECT query
    auto query = sqlgen::select<Book>();

    // Build WHERE conditions dynamically
    std::vector<sqlgen::Condition<Book>> conditions;

    // Add title keyword filter (LIKE search)
    if (filters.title_keyword.has_value() && !filters.title_keyword->empty()) {
        conditions.push_back(sqlgen::like(&Book::title, "%" + *filters.title_keyword + "%"));
    }

    // Add minimum year filter
    if (filters.min_year.has_value()) {
        conditions.push_back(sqlgen::ge(&Book::year, *filters.min_year));
    }

    // Add genre filter
    if (filters.genre.has_value() && !filters.genre->empty()) {
        conditions.push_back(sqlgen::eq(&Book::genre, *filters.genre));
    }

    // Add maximum price filter
    if (filters.max_price.has_value()) {
        conditions.push_back(sqlgen::le(&Book::price, *filters.max_price));
    }

    // Apply WHERE clauses if any conditions exist
    if (!conditions.empty()) {
        query = query.where(sqlgen::and_(conditions));
    }

    // Execute the query and return results
    return query.exec(db);
}

}  // namespace query_search_books_by_criteria
```

This implementation:

1. **Connects to the SQLite database** using `sqlgen::SQLiteDB`
2. **Starts with a base SELECT query** using `sqlgen::select<Book>()`
3. **Dynamically builds WHERE conditions** based on which filters are provided
4. **Uses appropriate SQL operators**:
   - `LIKE` with wildcards for title keyword search
   - `>=` (ge) for minimum year
   - `=` (eq) for genre
   - `<=` (le) for maximum price
5. **Combines conditions with AND** using `sqlgen::and_()`
6. **Executes the query** and returns the results

The function handles all optional parameters correctly - only adding WHERE clauses for filters that are actually provided (not null/empty).

