#pragma once

#include <filesystem>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

#include "eas_common.hpp"

namespace update_eas_table {

void update_eas_table() {
  design_eas_database_with_major();

  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // 1. Add a new column `Grade` to the table `Score`, with type `char(1)`, not allowing null values
  sqlgen::exec(conn, "ALTER TABLE Score ADD COLUMN Grade CHAR(1) NOT NULL DEFAULT 'A';").value();

  // 2. Modify the column type of `Age` in the table `Student` to `int`, allowing null values
  // Note: Since SQLite doesn't support direct column type modification, we need to:
  // a) Create a temporary table with the new schema
  // b) Copy data from old table to new table
  // c) Drop old table and rename new table

  // First check if Age column exists, if not add it
  sqlgen::exec(conn, R"(
    CREATE TABLE IF NOT EXISTS Student_temp (
      SNo VARCHAR(10) PRIMARY KEY,
      SName VARCHAR(30) NOT NULL,
      Sex INTEGER DEFAULT 1,
      Birthday DATETIME,
      Major INTEGER,
      Scorses REAL DEFAULT 0.0,
      Remark TEXT,
      Age INTEGER
    );
  )").value();

  // Copy data from old Student table to temp table
  sqlgen::exec(conn, R"(
    INSERT INTO Student_temp (SNo, SName, Sex, Birthday, Major, Scorses, Remark, Age)
    SELECT SNo, SName, Sex, Birthday, Major, Scorses, Remark, 
           CASE WHEN Age IS NULL THEN NULL ELSE CAST(Age AS INTEGER) END 
    FROM Student;
  )").value();

  // Drop old table and rename temp table
  sqlgen::exec(conn, "DROP TABLE Student;").value();
  sqlgen::exec(conn, "ALTER TABLE Student_temp RENAME TO Student;").value();

  // 3. Drop the table `Major`
  sqlgen::exec(conn, "DROP TABLE IF EXISTS Major;").value();
}

} // namespace update_eas_table

