bool upsert_inventory_items(const std::vector<Inventory>& items) {
  try {
    // Create database connection
    sqlgen::database<sqlgen::sqlite> db("test_db.sqlite");

    // Create table if it doesn't exist (assuming it exists per requirements, but adding safety)
    db.execute(R"(
      CREATE TABLE IF NOT EXISTS Inventory (
        item_id INTEGER PRIMARY KEY,
        name TEXT NOT NULL,
        quantity INTEGER NOT NULL
      )
    )");

    // Perform upsert operations using replace (SQLite's UPSERT equivalent)
    auto replace_stmt = db.replace<Inventory>();

    for (const auto& item : items) {
      replace_stmt(item);
    }

    // Verify upsert behavior by reading back items
    auto select_stmt = db.select<Inventory>().where(sqlgen::like(&Inventory::item_id, _));

    std::cout << "Verifying upsert operation..." << std::endl;
    std::cout << "Current inventory items:" << std::endl;
    std::cout << "item_id\tname\tquantity" << std::endl;

    bool all_found = true;
    for (const auto& original_item : items) {
      auto results = select_stmt(original_item.item_id);

      if (results.empty()) {
        std::cerr << "ERROR: Item with ID " << original_item.item_id << " not found after upsert!" << std::endl;
        all_found = false;
        continue;
      }

      const auto& retrieved_item = results.front();
      std::cout << retrieved_item.item_id << "\t" 
                << retrieved_item.name << "\t" 
                << retrieved_item.quantity << std::endl;

      // Verify data integrity
      if (retrieved_item.name != original_item.name || 
          retrieved_item.quantity != original_item.quantity) {
        std::cerr << "ERROR: Data mismatch for item ID " << original_item.item_id << std::endl;
        all_found = false;
      }
    }

    if (all_found) {
      std::cout << "Upsert verification successful! All items properly inserted/replaced." << std::endl;
    }

    return all_found;

  } catch (const std::exception& e) {
    std::cerr << "Database error: " << e.what() << std::endl;
