JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  JoinAnalysis analysis;

  // Create SQLite connection to in-memory database
  sqlgen::sqlite::connection conn(":memory:");

  // Create tables
  conn.execute(R"(
    CREATE TABLE Department (
      department_id INTEGER PRIMARY KEY,
      department_name TEXT NOT NULL,
      location TEXT
    )
  )");

  conn.execute(R"(
    CREATE TABLE Employee (
      employee_id INTEGER PRIMARY KEY,
      department_id INTEGER,
      first_name TEXT NOT NULL,
      last_name TEXT NOT NULL,
      salary REAL NOT NULL,
      FOREIGN KEY (department_id) REFERENCES Department(department_id)
    )
  )");

  // Insert department data
  for (const auto& dept : depts) {
    conn.execute("INSERT INTO Department (department_id, department_name, location) VALUES (?, ?, ?)",
                dept.department_id, dept.department_name, dept.location);
  }

  // Insert employee data
  for (const auto& emp : emps) {
    conn.execute("INSERT INTO Employee (employee_id, department_id, first_name, last_name, salary) VALUES (?, ?, ?, ?, ?)",
                emp.employee_id, emp.department_id, emp.first_name, emp.last_name, emp.salary);
  }

  // 1. INNER JOIN - Employees with assigned departments
  auto inner_join_stmt = conn.prepare(R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Department d
    INNER JOIN Employee e ON d.department_id = e.department_id
  )");

  inner_join_stmt.execute([&analysis](const std::string& department_name, 
                                     const std::string& first_name, 
                                     const std::string& last_name, 
                                     double salary) {
    analysis.inner_join_results.push_back(JoinResult{
      department_name, first_name, last_name, salary
    });
    return true;
  });

  // 2. LEFT JOIN - All employees (even without departments)
  auto left_join_stmt = conn.prepare(R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Employee e
    LEFT JOIN Department d ON e.department_id = d.department_id
  )");

  left_join_stmt.execute([&analysis](const std::optional<std::string>& department_name, 
                                    const std::string& first_name, 
                                    const std::string& last_name, 
                                    double salary) {
    analysis.left_join_results.push_back(JoinResult{
      department_name, first_name, last_name, salary
    });
    return true;
  });

  // 3. RIGHT JOIN - All departments (even without employees)
  // SQLite doesn't support RIGHT JOIN directly, so we simulate it with LEFT JOIN
  auto right_join_stmt = conn.prepare(R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Department d
    LEFT JOIN Employee e ON d.department_id = e.department_id
  )");

  right_join_stmt.execute([&analysis](const std::string& department_name, 
                                     const std::optional<std::string>& first_name, 
                                     const std::optional<std::string>& last_name, 
                                     const std::optional<double>& salary) {
    analysis.right_join_results.push_back(JoinResult{
      department_name, first_name, last_name, salary
    });
    return true;
  });

  // 4. FULL JOIN - All employees and departments
  // SQLite doesn't support FULL JOIN directly, so we simulate it with UNION of LEFT and RIGHT joins
  auto full_join_stmt = conn.prepare(R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Employee e
    LEFT JOIN Department d ON e.department_id = d.department_id

    UNION

    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Department d
    LEFT JOIN Employee e ON d.department_id = e.department_id
    WHERE e.employee_id IS NULL
  )");

  full_join_stmt.execute([&analysis](const std::optional<std::string>& department_name, 
                                    const std::optional<std::string>& first_name, 
                                    const std::optional<std::string>& last_name, 
                                    const std::optional<double>& salary) {
    analysis.full_join_results.push_back(JoinResult{
      department_name, first_name, last_name, salary
    });
    return true;
  });

  return analysis;
}

}  // namespace analyze_department_employees

