```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  // Connect to the SQLite database
  sqlgen::SQLiteDB db("test_db.sqlite");

  // Create the SQL query to extract weekday from sale_time and aggregate totals
  // Using SQLite's strftime function with '%w' format to get weekday (0-6, where 0 is Sunday)
  auto query = sqlgen::query<Sales>{}
      .select(
          sqlgen::cast(sqlgen::strftime("%w", Sales::sale_time), "INTEGER").as("weekday"),
          sqlgen::sum(Sales::quantity).as("total_quantity")
      )
      .group_by(sqlgen::strftime("%w", Sales::sale_time))
      .order_by(sqlgen::strftime("%w", Sales::sale_time));

  // Execute the query and get results
  auto results = db.select(query);

  // Convert the results to WeekdayStats vector
  std::vector<WeekdayStats> weekday_stats;
  weekday_stats.reserve(results.size());

  for (const auto& row : results) {
    WeekdayStats stats;
    stats.weekday = std::get<0>(row); // weekday
    stats.total_quantity = std::get<1>(row); // total_quantity
    weekday_stats.push_back(stats);
  }

  return weekday_stats;
}

}  // namespace weekday_sales_analysis
```

